// Complex subsystem classes
class CPU {
  freeze() { console.log('CPU: freezing...'); }
  jump(position) { console.log(`CPU: jumping to position ${position}`); }
  execute() { console.log('CPU: executing instructions'); }
}

class Memory {
  load(position, data) {
    console.log(`Memory: loading "${data}" at position ${position}`);
  }
}

class HardDrive {
  read(lba, size) {
    return `OS boot sector (lba=${lba}, size=${size} bytes)`;
  }
}

// Facade — simple interface to the complex subsystem
class ComputerFacade {
  #cpu;
  #memory;
  #hardDrive;

  constructor() {
    this.#cpu = new CPU();
    this.#memory = new Memory();
    this.#hardDrive = new HardDrive();
  }

  start() {
    this.#cpu.freeze();
    const bootData = this.#hardDrive.read(0, 1024);
    this.#memory.load(0, bootData);
    this.#cpu.jump(0);
    this.#cpu.execute();
    console.log('Computer started successfully!');
  }
}

// Client code — only interacts with the Facade
const computer = new ComputerFacade();
computer.start();
// CPU: freezing...
// Memory: loading "OS boot sector (lba=0, size=1024 bytes)" at position 0
// CPU: jumping to position 0
// CPU: executing instructions
// Computer started successfully!

