class CPU:
    def freeze(self) -> None:
        print("CPU: freezing...")

    def jump(self, position: int) -> None:
        print(f"CPU: jumping to position {position}")

    def execute(self) -> None:
        print("CPU: executing instructions")


class Memory:
    def load(self, position: int, data: str) -> None:
        print(f'Memory: loading "{data}" at position {position}')


class HardDrive:
    def read(self, lba: int, size: int) -> str:
        return f"OS boot sector (lba={lba}, size={size} bytes)"


# Facade — simple interface to the complex subsystem
class ComputerFacade:
    def __init__(self) -> None:
        self._cpu = CPU()
        self._memory = Memory()
        self._hard_drive = HardDrive()

    def start(self) -> None:
        self._cpu.freeze()
        boot_data = self._hard_drive.read(0, 1024)
        self._memory.load(0, boot_data)
        self._cpu.jump(0)
        self._cpu.execute()
        print("Computer started successfully!")


# Client code — only interacts with the Facade
computer = ComputerFacade()
computer.start()
# CPU: freezing...
# Memory: loading "OS boot sector (lba=0, size=1024 bytes)" at position 0
# CPU: jumping to position 0
# CPU: executing instructions
# Computer started successfully!
